import React, { useState, useEffect } from 'react';
import './App.css';
import Terminal from './Terminal';
import Taskbar from './Taskbar';

const App = () => {
  const [activeApp, setActiveApp] = useState(null);

  useEffect(() => {
    const handleScroll = () => {
      const taskbar = document.querySelector('.taskbar');
      const taskbarApps = document.querySelectorAll('.taskbar-app');
      const scrollY = window.scrollY;

      if (scrollY >= 300) {
        taskbar.classList.add('taskbar-visible');
        taskbarApps.forEach((app, index) => {
          app.style.transitionDelay = `${index * 0.1}s`;
          app.classList.add('taskbar-app-visible');
        });
      } else {
        taskbar.classList.remove('taskbar-visible');
        taskbarApps.forEach((app) => {
          app.style.transitionDelay = '0s';
          app.classList.remove('taskbar-app-visible');
        });
      }
    };

    window.addEventListener('scroll', handleScroll);

    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  const handleMouseEnter = (event) => {
    const app = event.target;
    app.classList.add('taskbar-app-hover');
  };

  const handleMouseLeave = (event) => {
    const app = event.target;
    app.classList.remove('taskbar-app-hover');
  };

  const handleClick = (event) => {
    const app = event.target;
    const appName = app.innerText;

    if (appName !== activeApp) {
      setActiveApp(appName);
    } else {
      setActiveApp(null);
    }
  };

  return (
    <div className="App">
      <header className="App-header">
        <Terminal activeApp={activeApp} />
        <Taskbar
          handleMouseEnter={handleMouseEnter}
          handleMouseLeave={handleMouseLeave}
          handleClick={handleClick}
        />
      </header>
    </div>
  );
};

export default App;
